    install(Auth) {
        // DEFAULT true registers Android lifecycle callbacks that CLEAR the session
        // in background -> widget reads null token -> anon -> RLS empty. Turn OFF.
        enableLifecycleCallbacks = false
        // autoLoadFromStorage stays true (default): session restored from encrypted storage at init
        alwaysAutoRefresh = true
    }
