    install(Realtime)    // requires realtime-kt dependency (currently MISSING)
}

// realtime-kt extension: initial select + postgres_changes merged, keyed by PK
val liveTodos: Flow<List<Todo>> = client.from("todos").selectAsFlow(Todo::id)

// Repository: pipe into Room; UI + widget observe Room, not the network
scope.launch {
    client.auth.awaitInitialization()                 // ensure session before subscribing (RLS)
    liveTodos.catch { /* keep last Room data on error */ }
        .collect { rows -> todoDao.replaceAll(rows.map { it.toEntity() }) }
}
// UI:
val todos by todoDao.observeAll().collectAsStateWithLifecycle(emptyList())

val channel = client.channel("todos-changes")
val changes = channel.postgresChangeFlow<PostgresAction>(schema = "public") { table = "todos" }
scope.launch {
    changes.collect { action -> when (action) {
        is PostgresAction.Insert -> todoDao.upsert(action.decodeRecord<Todo>().toEntity())
        is PostgresAction.Update -> todoDao.upsert(action.decodeRecord<Todo>().toEntity())
        is PostgresAction.Delete -> todoDao.deleteById(action.oldRecord["id"]!!.jsonPrimitive.content)
        else -> {}
    } }
}
channel.subscribe()   // opens socket; unsubscribe()/removeChannel on teardown

when (val s = client.auth.sessionStatus.collectAsStateWithLifecycle().value) {
    is SessionStatus.Initializing -> SplashLoader()
    is SessionStatus.Authenticated -> TodoScreen(repo)
    is SessionStatus.RefreshFailure -> TodoScreen(repo, offline = true) // show cached Room
    is SessionStatus.NotAuthenticated -> SignIn { }
}

