// Widget WRITES still go through the shared client, not hand-built JSON:
suspend fun toggle(id: String, done: Boolean) =
    client.from("todos").update({ set("done", done) }) { filter { eq("id", id) } }

suspend fun refreshTodos() = try {
    client.auth.refreshCurrentSession()      // we own refresh now
    client.from("todos").select().decodeList<Todo>()
} catch (e: RestException) {
    if (e.statusCode == 401 || e.statusCode == 403) { /* auth-fail: re-auth, keep Room */ }
    else throw e                              // data-fail: surface
}

@Entity(tableName = "quote")
data class QuoteEntity(@PrimaryKey val id: Int = 0, val text: String, val fetchedAt: Long)

@Dao
interface QuoteDao {
    @Query("SELECT * FROM quote WHERE id = 0")
    fun observe(): Flow<QuoteEntity?>            // read path (app AND widget)
    @Query("SELECT * FROM quote WHERE id = 0")
    suspend fun getOnce(): QuoteEntity?           // for classic widget synchronous read
    @Upsert suspend fun upsert(q: QuoteEntity)    // write path
}

class QuoteRepository(private val dao: QuoteDao, private val api: QuoteApi) {
    val stream: Flow<QuoteEntity?> = dao.observe()

    // Called by: app foreground, FCM handler, user action, periodic Worker.
    suspend fun refresh(context: Context) = withContext(Dispatchers.IO) {
        val dto = api.fetch()                     // OkHttp/SDK here, NOT in the widget
        dao.upsert(QuoteEntity(text = dto.text, fetchedAt = System.currentTimeMillis()))
        QuoteWidget().updateAll(context)          // immediate cross-process refresh
    }
}

class QuoteWidget : GlanceAppWidget() {
    override suspend fun provideGlance(context: Context, id: GlanceId) {
        val repo = ServiceLocator.quoteRepository(context)
        provideContent {
            val quote by repo.stream.collectAsState(initial = null) // MUST be inside provideContent
            when (quote) {
                null -> Text("Loading…")
                else -> Column {
                    Text(quote!!.text)
                    // manual refresh button -> same single writer
                    Button("Refresh", onClick = actionRunCallback<RefreshAction>())
                }
            }
        }
    }
}

class RefreshAction : ActionCallback {
    override suspend fun onAction(context: Context, glanceId: GlanceId, params: ActionParameters) {
        ServiceLocator.quoteRepository(context).refresh(context) // writes Room -> collectAsState redraws
    }
}

class RefreshWorker(ctx: Context, p: WorkerParameters) : CoroutineWorker(ctx, p) {
    override suspend fun doWork(): Result = try {
        ServiceLocator.quoteRepository(applicationContext).refresh(applicationContext)
        Result.success()
    } catch (e: IOException) { Result.retry() }   // backoff kicks in
}

fun scheduleRefresh(context: Context) {
    val req = PeriodicWorkRequestBuilder<RefreshWorker>(15, TimeUnit.MINUTES)
        .setConstraints(Constraints.Builder()
            .setRequiredNetworkType(NetworkType.CONNECTED)
            .setRequiresBatteryNotLow(true).build())
        .setBackoffCriteria(BackoffPolicy.EXPONENTIAL, 30, TimeUnit.SECONDS)
        .build()
    WorkManager.getInstance(context).enqueueUniquePeriodicWork(
        "quote_widget_refresh",
        ExistingPeriodicWorkPolicy.KEEP,   // or UPDATE (WM 2.8+) to change params keeping schedule
        req)
}
