// Shimmer brush (respect reduced-motion by freezing offset):
@Composable fun Modifier.shimmer(): Modifier {
  val x by rememberInfiniteTransition("sh").animateFloat(-2f, 2f,
    infiniteRepeatable(tween(1100, easing = LinearEasing)), label="x")
  val c = Color.White.copy(0.06f); val hi = Color.White.copy(0.16f)
  return background(Brush.linearGradient(listOf(c, hi, c),
    start = Offset(x*300f, 0f), end = Offset(x*300f+300f, 0f)))
}
